const CHANNEL_MAP = {
  SAT_MYTH:        { channelId: '6a5517eb80cc80cdcaac2ddf', account: 1, name: 'athenalearns' },
  BRAIN_TEASER:    { channelId: '6a551bc880cc80cdcaac4e2d', account: 1, name: 'athenastudy' },
  COMIC:           { channelId: '6a5518d580cc80cdcaac30f5', account: 1, name: 'athenastudies_' },
  NOTES_APP:       { channelId: '6a552a2280cc80cdcaac9e06', account: 2, name: 'athena.study' },
  BEAGLE_EXPLAINS: { channelId: '6a555a1e80cc80cdcaad980f', account: 2, name: 'athena_study' }
};

const config = $('Read Config Sheet').all();
const configMap = {};
config.forEach(item => { configMap[item.json.category] = item.json; });

const review = $('Read Review Sheet').all();

// Rows marked Post (case-insensitive), with a drive link present
const postable = review.filter(i => {
  const status = String(i.json.status || '').trim().toLowerCase();
  const hasLink = (i.json.drive_link || '').includes('drive.google.com');
  return status === 'post' && hasLink;
});

// Group by category
const byCategory = {};
postable.forEach(i => {
  const cat = i.json.category;
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(i.json);
});

// For each category with >= 5, take the 5 oldest (by timestamp), flatten to per-image items
const IMAGES_PER_POST = 5;
const out = [];

Object.keys(byCategory).forEach(cat => {
  const rows = byCategory[cat];
  if (rows.length < IMAGES_PER_POST) return; // skip category — not enough marked

  const channel = CHANNEL_MAP[cat];
  if (!channel) return; // unknown category — skip rather than post to wrong account

  const caption = (configMap[cat] || {}).post_caption || '';

  rows.sort((a, b) => String(a.timestamp || '').localeCompare(String(b.timestamp || '')));
  const selected = rows.slice(0, IMAGES_PER_POST);

  selected.forEach((row, idx) => {
    // Extract Drive file id from uc?id=FILE_ID link
    const m = String(row.drive_link || '').match(/[?&]id=([A-Za-z0-9_-]+)/);
    const driveFileId = m ? m[1] : null;
    if (!driveFileId) return;

    out.push({
      json: {
        category: cat,
        buffer_channel_id: channel.channelId,
        buffer_account: channel.account,
        channel_name: channel.name,
        post_caption: caption,
        idea_id: row['idea_id '] || row.idea_id || '',
        drive_file_id: driveFileId,
        image_order: idx
      }
    });
  });
});

if (out.length === 0) {
  throw new Error('No categories have 5+ rows marked Post in the Review sheet. Mark at least 5 rows in one category (status column = Post) and re-run.');
}

return out;

const original = $('Post Loop').item.json;
const resp = $json;

const url = resp.secure_url || resp.url;
if (!url) throw new Error('Cloudinary upload failed — no secure_url in response: ' + JSON.stringify(resp).substring(0, 300));

return [{ json: Object.assign({}, original, { cloudinary_url: url }) }];

// Items arrive from the loop 'done' port with cloudinary_url attached
const items = $input.all().map(i => i.json);

// Group back by category
const byCategory = {};
items.forEach(it => {
  if (!byCategory[it.category]) byCategory[it.category] = [];
  byCategory[it.category].push(it);
});

const out = [];
Object.keys(byCategory).forEach(cat => {
  const group = byCategory[cat].sort((a, b) => a.image_order - b.image_order);
  if (group.length < 5) return; // an upload failed somewhere — don't post partial carousels

  const first = group[0];

  // Escape caption for embedding in GraphQL string
  const caption = String(first.post_caption || '')
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, '\\n');

  const assetsBlock = group.map(g =>
    '{ image: { url: "' + g.cloudinary_url + '" } }'
  ).join('\n        ');

  const mutation = `mutation CreatePost {
  createPost(
    input: {
      text: "${caption}"
      channelId: "${first.buffer_channel_id}"
      schedulingType: automatic
      mode: addToQueue
      assets: [
        ${assetsBlock}
      ]
    }
  ) {
    ... on PostActionSuccess {
      post { id }
    }
    ... on MutationError {
      message
    }
  }
}`;

  out.push({
    json: {
      category: cat,
      buffer_account: first.buffer_account,
      channel_name: first.channel_name,
      idea_ids: group.map(g => g.idea_id),
      graphql_body: { query: mutation }
    }
  });
});

if (out.length === 0) {
  throw new Error('No complete 5-image groups survived the upload step. Check Cloudinary upload results.');
}

return out;

const resp = $json;
const original = $input.first().json;

// GraphQL always returns 200; errors live in the body
const postResult = (resp.data && resp.data.createPost) || {};
const success = !!(postResult.post && postResult.post.id);
const errorMsg = postResult.message || (resp.errors ? JSON.stringify(resp.errors).substring(0, 300) : '');

if (!success) {
  throw new Error('Buffer post failed for ' + (original.channel_name || 'unknown channel') + ': ' + (errorMsg || 'unknown error'));
}

// Fan out one item per idea_id so the Sheets update node marks each row
const ids = original.idea_ids || [];
return ids.map(id => ({
  json: {
    idea_id: id,
    category: original.category,
    buffer_post_id: postResult.post.id,
    new_status: 'Posted'
  }
}));

